from flask import Blueprint, request, jsonifyfrom controller.backup_controller import BackupControllerfrom utils import parse_responsefrom config.data.constant import REDIRECT_ROUTErouter_backup = Blueprint("backup", __name__)@router_backup.route("", methods=["GET", "POST"], strict_slashes=REDIRECT_ROUTE)def handle_backup():    print(f"Incoming request URL: {request.url}")    if request.method == 'GET':        try:            # Methode aufrufen!            result = BackupController.fetch()        except Exception as e:            return jsonify({"error": str(e)}), 500    elif request.method == 'POST':        try:            result = BackupController.handle(request.form)        except Exception as e:            return jsonify({"error": str(e)}), 500    else:        return jsonify({"error": "Methode nicht erlaubt."}), 405    response, status = parse_response(result)    return jsonify(response), status